private void drawPentagram(Graphics2D g, int len, int x, int y,
Color fill, Color stroke) {
double angle = 0;

Path2D p = new Path2D.Float();
p.moveTo(x, y);

for (int i = 0; i < 5; i++) {
int x2 = x + (int) (Math.cos(angle) * len);
int y2 = y + (int) (Math.sin(-angle) * len);
p.lineTo(x2, y2);
x = x2;
y = y2;
angle -= degrees144;
}
p.closePath();

g.setColor(fill);
g.fill§;

g.setColor(stroke);
g.draw§;
}

